import {{hashlib}}
import {{secrets}}
import sqlite3

# Hashování hesla se solí
def hash_password(password: str) -> tuple[str, str]:
    salt = secrets.{{token_hex}}(16)
    pwd_hash = hashlib.{{sha256}}((salt + password).encode()).{{hexdigest}}()
    return salt, pwd_hash

def verify_password(password: str, salt: str, stored_hash: str) -> bool:
    pwd_hash = hashlib.sha256(({{salt}} + password).encode()).hexdigest()
    return {{secrets}}.compare_digest(pwd_hash, stored_hash)

# Bezpečný parametrizovaný SQL dotaz
def get_user(conn, username: str):
    cursor = conn.{{cursor}}()
    # NIKDY: f"SELECT * FROM users WHERE name='{username}'"  ← SQL injection!
    cursor.execute("SELECT * FROM users WHERE name = ?", ({{username}},))
    return cursor.{{fetchone}}()

const {{crypto}} = require('crypto');
const db = require('./db');   // parameterized query wrapper

// Hashování hesla
function hashPassword(password) {
    const salt = crypto.{{randomBytes}}(16).toString('hex');
    const hash = crypto.{{createHmac}}('sha256', salt)
                       .update({{password}})
                       .digest('hex');
    return { salt, {{hash}} };
}

function verifyPassword(password, salt, storedHash) {
    const hash = crypto.createHmac('sha256', {{salt}})
                       .update(password)
                       .digest('{{hex}}');
    return crypto.{{timingSafeEqual}}(Buffer.from(hash), Buffer.from(storedHash));
}

// Bezpečný parametrizovaný dotaz
async function getUser(username) {
    // Nikdy: `SELECT * FROM users WHERE name='${username}'`
    return db.query('SELECT * FROM users WHERE name = ?', [{{username}}]);
